  }),
  resolvedByUser: one(users, {
    fields: [unavailabilityEvents.resolvedBy],
    references: [users.id],
  }),
}));

export const trainRouteCompatibilityRelations = relations(trainRouteCompatibility, ({ one }) => ({
  train: one(trains, {
    fields: [trainRouteCompatibility.trainId],
    references: [trains.id],
  }),
  fleet: one(fleets, {
    fields: [trainRouteCompatibility.fleetId],
    references: [fleets.id],
