export const inventoryPositionsRelations = relations(inventoryPositions, ({ one, many }) => ({
  depot: one(depots, {
    fields: [inventoryPositions.depotId],
    references: [depots.id],
  }),
  reservations: many(materialReservations),
}));

export const materialReservationsRelations = relations(materialReservations, ({ one }) => ({
  pmScheduleRecord: one(pmSchedule, {
    fields: [materialReservations.pmScheduleId],
    references: [pmSchedule.id],
  }),
  inventoryPosition: one(inventoryPositions, {
    fields: [materialReservations.inventoryPositionId],
    references: [inventoryPositions.id],
  }),
  reservedByUser: one(users, {
    fields: [materialReservations.reservedBy],
    references: [users.id],
  }),
}));

/**
 * MMS Track Capabilities Tables (v2.1)
 *
 * Track equipment/features and PM requirements for constraint-based scheduling.
 * Also includes PM baseline assumptions for cold start data migration.
 *
 * @see specs/003-database-schema.md Sections 3.2.5 - 3.2.6
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  date,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
} from 'drizzle-orm/pg-core';
import { tracks, trains } from './core-fleet';
import {
  assumptionTypeEnum,
  confidenceLevelEnum,
  trackCapabilityEnum,
} from './enums';
import { pmTypes } from './pm-management';
import { users } from './users';

/**
 * Track Capabilities - Equipment and features per track
 *
 * Defines specific equipment available on each maintenance track.
 * Used to match PM requirements to capable tracks.
 *
 * Examples:
 * - Track T1 at Bishan has: PIT, CRANE, LIFTING_JACKS
 * - Track T5 at Changi has: WHEEL_LATHE, DROP_TABLE
 */
export const trackCapabilities = pgTable(
  'track_capabilities',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trackId: uuid('track_id')
      .notNull()
      .references(() => tracks.id),
    capability: trackCapabilityEnum('capability').notNull(),

    // Capacity limits for this capability (e.g., max lift weight)
    capacityLimit: jsonb('capacity_limit'), // {"max_axle_load_tonnes": 17, "max_lift_tonnes": 25}

    // Availability
    isOperational: boolean('is_operational').default(true),
    maintenanceSchedule: text('maintenance_schedule'), // "Unavailable Tuesdays 06:00-10:00"

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_track_cap_unique').on(table.trackId, table.capability),
    index('idx_track_cap_track').on(table.trackId),
    index('idx_track_cap_type').on(table.capability),
  ]
);

/**
 * PM Capability Requirements - What capabilities each PM type needs
 *
 * Links PM types to required track capabilities.
 * Mandatory vs. preferred:
 * - is_mandatory=true: PM cannot proceed without this capability
 * - is_mandatory=false: Preferred but can use alternative
 *
 * Example: C4 overhaul requires PIT (mandatory), LIFTING_JACKS (mandatory), CRANE (preferred)
 */
export const pmCapabilityRequirements = pgTable(
  'pm_capability_requirements',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    capability: trackCapabilityEnum('capability').notNull(),
    isMandatory: boolean('is_mandatory').default(true),

    notes: text('notes'), // Why this capability is needed

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_pm_cap_req_unique').on(table.pmTypeId, table.capability),
    index('idx_pm_cap_req_pm').on(table.pmTypeId),
    index('idx_pm_cap_req_cap').on(table.capability),
  ]
);

/**
 * PM Baseline Assumptions - Cold start data migration
 *
 * Handles scenarios where PM history is incomplete during data migration.
 * Tracks how PM dates/mileage were inferred with confidence levels.
 *
 * Inference rules (implemented in application logic):
 * 1. INFERRED_FROM_COMMISSIONING: If train commissioned 2020-01-01 and C1 interval
 *    is 6 months, assume first PM at 2020-07-01
 * 2. INFERRED_FROM_HIGHER_PM: If C4 completed 2024-06-15, C1/C2/C3 counters reset
 *    from that date
 * 3. NO_HISTORY: No data, use commissioning date with requires_review=true
 *
 * Records with LOW/ESTIMATED confidence should have requires_review=true
 * for manual verification by operators.
 */
export const pmBaselineAssumptions = pgTable(
  'pm_baseline_assumptions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),

    // Assumption details
    assumptionType: assumptionTypeEnum('assumption_type').notNull(),

    // Assumed baseline values
    assumedLastPmDate: date('assumed_last_pm_date'),
    assumedLastPmMileage: integer('assumed_last_pm_mileage'),
    confidenceLevel: confidenceLevelEnum('confidence_level').notNull(),

    // Inference source documentation
    inferenceSource: text('inference_source'), // How assumption was derived
    inferenceData: jsonb('inference_data'), // Supporting data

    // Review workflow
    requiresReview: boolean('requires_review').default(false),
    reviewedBy: uuid('reviewed_by').references(() => users.id),
    reviewedAt: timestamp('reviewed_at', { withTimezone: true }),
    reviewNotes: text('review_notes'),

    // When applied to the system
    appliedAt: timestamp('applied_at', { withTimezone: true }),
    appliedBy: uuid('applied_by').references(() => users.id),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_assumptions_unique').on(table.trainId, table.pmTypeId),
    index('idx_assumptions_train').on(table.trainId),
    index('idx_assumptions_review').on(table.requiresReview),
    index('idx_assumptions_confidence').on(table.confidenceLevel),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const trackCapabilitiesRelations = relations(trackCapabilities, ({ one }) => ({
  track: one(tracks, {
    fields: [trackCapabilities.trackId],
    references: [tracks.id],
  }),
}));

export const pmCapabilityRequirementsRelations = relations(pmCapabilityRequirements, ({ one }) => ({
  pmType: one(pmTypes, {
    fields: [pmCapabilityRequirements.pmTypeId],
    references: [pmTypes.id],
  }),
}));

export const pmBaselineAssumptionsRelations = relations(pmBaselineAssumptions, ({ one }) => ({
  train: one(trains, {
    fields: [pmBaselineAssumptions.trainId],
    references: [trains.id],
  }),
  pmType: one(pmTypes, {
    fields: [pmBaselineAssumptions.pmTypeId],
    references: [pmTypes.id],
  }),
  reviewedByUser: one(users, {
    fields: [pmBaselineAssumptions.reviewedBy],
    references: [users.id],
    relationName: 'reviewedBy',
  }),
  appliedByUser: one(users, {
    fields: [pmBaselineAssumptions.appliedBy],
    references: [users.id],
    relationName: 'appliedBy',
  }),
}));

/**
 * MMS Baseline & Drift Tables
 *
 * Plan stability through immutable baseline snapshots and drift monitoring.
 *
 * Baseline/Drift Architecture:
 * - Baselines are published snapshots of the PM schedule and mileage projections
 * - Drift analysis compares current state to baseline
 * - When drift exceeds thresholds, requires_replan flag is set
 *
 * Drift thresholds:
 * - Mileage: ±5.0%
 * - Schedule: ±14 days
 * - Fleet: ≥5 trains requiring replan
 *
 * @see specs/003-database-schema.md Section 3.8
 */

import { relations, sql } from 'drizzle-orm';
import {
  boolean,
  date,
  decimal,
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots, trains } from './core-fleet';
import { baselineStatusEnum } from './enums';
import { pmTypes } from './pm-management';
import { users } from './users';

/**
 * Plan Baselines - Immutable schedule snapshots
 *
 * A baseline captures the state of PM scheduling and mileage projections
 * at a point in time. Published baselines become the reference for drift analysis.
 *
 * Status lifecycle:
 * DRAFT -> PUBLISHED -> SUPERSEDED (when new baseline published)
 */
export const planBaselines = pgTable(
  'plan_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),
    version: varchar('version', { length: 20 }).notNull(), // 'v3.2'

    baselineDate: date('baseline_date').notNull(), // "As of" date
    horizonEnd: date('horizon_end').notNull(), // How far into future

    // Workflow
    status: baselineStatusEnum('status').default('DRAFT'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    publishedBy: uuid('published_by').references(() => users.id),
    publishedAt: timestamp('published_at', { withTimezone: true }),

    supersededBy: uuid('superseded_by'),
    supersededAt: timestamp('superseded_at', { withTimezone: true }),

    // Metrics at baseline time
    fleetCount: integer('fleet_count'),
    totalPmScheduled: integer('total_pm_scheduled'),
    totalManhourProjected: decimal('total_manhour_projected', { precision: 12, scale: 2 }),
  },
  (table) => [
    index('idx_baselines_status').on(table.status),
    index('idx_baselines_date').on(table.baselineDate),
  ]
);

/**
 * Baseline PM Schedule - Snapshot of scheduled maintenance
 *
 * Immutable copy of PM schedule at baseline time.
 * Used for drift comparison.
 */
export const baselinePmSchedule = pgTable(
  'baseline_pm_schedule',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    pmTypeId: uuid('pm_type_id')
      .notNull()
      .references(() => pmTypes.id),
    projectedDate: date('projected_date').notNull(),
    projectedMileageKm: integer('projected_mileage_km'),

    assignedDepotId: uuid('assigned_depot_id').references(() => depots.id),
    assignedHours: decimal('assigned_hours', { precision: 6, scale: 2 }),
  },
  (table) => [
    uniqueIndex('idx_baseline_pm_unique').on(
      table.baselineId,
      table.trainId,
      table.pmTypeId,
      table.projectedDate
    ),
    index('idx_baseline_pm_baseline').on(table.baselineId),
    index('idx_baseline_pm_train').on(table.trainId, table.projectedDate),
  ]
);

/**
 * Baseline Mileage Projection - Snapshot of mileage forecasts
 *
 * Immutable copy of mileage projections at baseline time.
 * Used for drift comparison.
 */
export const baselineMileageProjection = pgTable(
  'baseline_mileage_projection',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id, { onDelete: 'cascade' }),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),
    projectionDate: date('projection_date').notNull(),
    projectedCumulativeKm: integer('projected_cumulative_km').notNull(),
    dailyRateKm: integer('daily_rate_km'), // Assumed daily accrual rate
  },
  (table) => [
    uniqueIndex('idx_baseline_mileage_unique').on(
      table.baselineId,
      table.trainId,
      table.projectionDate
    ),
    index('idx_baseline_mileage').on(table.baselineId, table.trainId),
  ]
);

/**
 * Drift Analysis - Comparison results
 *
 * Generated by drift monitor (nightly job).
 * Compares current state to baseline and flags trains requiring replan.
 */
export const driftAnalysis = pgTable(
  'drift_analysis',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    baselineId: uuid('baseline_id')
      .notNull()
      .references(() => planBaselines.id),
    analysisDate: date('analysis_date').notNull(),

    trainId: uuid('train_id')
      .notNull()
      .references(() => trains.id),

    // Mileage drift
    baselineProjectedKm: integer('baseline_projected_km').notNull(),
    actualKm: integer('actual_km').notNull(),
    // Generated column: mileage drift (positive = traveled more than projected)
    mileageDriftKm: integer('mileage_drift_km').generatedAlwaysAs(
      sql`actual_km - baseline_projected_km`
    ),
    mileageDriftPct: decimal('mileage_drift_pct', { precision: 5, scale: 2 }),

    // Schedule drift (days)
    avgPmDriftDays: decimal('avg_pm_drift_days', { precision: 5, scale: 1 }),
    maxPmDriftDays: integer('max_pm_drift_days'),

    // Threshold breach
    requiresReplan: boolean('requires_replan').default(false),
    replanReason: text('replan_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_drift_unique').on(table.baselineId, table.trainId, table.analysisDate),
    index('idx_drift_baseline').on(table.baselineId, table.analysisDate),
    index('idx_drift_replan').on(table.requiresReplan, table.analysisDate),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const planBaselinesRelations = relations(planBaselines, ({ one, many }) => ({
  createdByUser: one(users, {
    fields: [planBaselines.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
  publishedByUser: one(users, {
    fields: [planBaselines.publishedBy],
    references: [users.id],
    relationName: 'publishedBy',
  }),
  supersededByBaseline: one(planBaselines, {
    fields: [planBaselines.supersededBy],
    references: [planBaselines.id],
    relationName: 'supersedes',
  }),
  pmScheduleSnapshots: many(baselinePmSchedule),
  mileageProjections: many(baselineMileageProjection),
  driftAnalyses: many(driftAnalysis),
}));

export const baselinePmScheduleRelations = relations(baselinePmSchedule, ({ one }) => ({
  baseline: one(planBaselines, {
    fields: [baselinePmSchedule.baselineId],
    references: [planBaselines.id],
  }),
  train: one(trains, {
    fields: [baselinePmSchedule.trainId],
    references: [trains.id],
  }),
  pmType: one(pmTypes, {
    fields: [baselinePmSchedule.pmTypeId],
    references: [pmTypes.id],
  }),
  assignedDepot: one(depots, {
    fields: [baselinePmSchedule.assignedDepotId],
    references: [depots.id],
  }),
}));

export const baselineMileageProjectionRelations = relations(
  baselineMileageProjection,
  ({ one }) => ({
    baseline: one(planBaselines, {
      fields: [baselineMileageProjection.baselineId],
      references: [planBaselines.id],
    }),
    train: one(trains, {
      fields: [baselineMileageProjection.trainId],
      references: [trains.id],
    }),
  })
);

export const driftAnalysisRelations = relations(driftAnalysis, ({ one }) => ({
  baseline: one(planBaselines, {
    fields: [driftAnalysis.baselineId],
    references: [planBaselines.id],
  }),
  train: one(trains, {
    fields: [driftAnalysis.trainId],
    references: [trains.id],
  }),
}));

/**
 * MMS Costing Tables
 *
 * Financial tracking for maintenance operations.
 * Used for TCO (Total Cost of Ownership) projections over the 12-year contract.
 *
 * Cost components:
 * - Labor: Hourly rates with shift/weekend/holiday multipliers
 * - Materials: Part costs with effective dating
 * - Overhead: 18% of direct costs (standard industry rate)
 *
 * TCO projection parameters:
 * - Inflation: 3% annually
 * - Discount rate: 5% for NPV calculations
 *
 * @see specs/003-database-schema.md Section 3.10
 */

import { relations, sql } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  pgTable,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';

/**
 * Labor Rates - Hourly costs for maintenance work
 *
 * Rates can be depot-specific or global (depot_id = NULL).
 * Includes multipliers for overtime, weekend, and holiday work.
 */
export const laborRates = pgTable(
  'labor_rates',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    depotId: uuid('depot_id').references(() => depots.id), // NULL = global default
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    // Rate types
    regularHourlyRate: decimal('regular_hourly_rate', { precision: 10, scale: 2 }).notNull(),
    overtimeMultiplier: decimal('overtime_multiplier', { precision: 3, scale: 2 }).default('1.5'),
    weekendMultiplier: decimal('weekend_multiplier', { precision: 3, scale: 2 }).default('2.0'),
    holidayMultiplier: decimal('holiday_multiplier', { precision: 3, scale: 2 }).default('2.5'),

    // Shop rate (fully loaded with overhead, benefits, etc.)
    shopRateHourly: decimal('shop_rate_hourly', { precision: 10, scale: 2 }),

    currency: varchar('currency', { length: 3 }).default('SGD'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_labor_rates_depot_date').on(table.depotId, table.effectiveFrom),
    index('idx_labor_rates_depot').on(table.depotId),
  ]
);

/**
 * Material Costs - Part pricing history
 *
 * Historical part prices for accurate cost calculation.
 * Effective dating allows for price changes over time.
 */
export const materialCosts = pgTable(
  'material_costs',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    partNumber: varchar('part_number', { length: 50 }).notNull(),
    effectiveFrom: date('effective_from').notNull(),
    effectiveTo: date('effective_to'),

    unitCost: decimal('unit_cost', { precision: 12, scale: 2 }).notNull(),
    currency: varchar('currency', { length: 3 }).default('SGD'),
    supplier: varchar('supplier', { length: 100 }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_material_costs_part_date').on(table.partNumber, table.effectiveFrom),
    index('idx_material_costs_part').on(table.partNumber),
  ]
);

/**
 * Cost Baselines - Budget vs. Actual tracking
 *
 * Annual cost tracking for variance analysis.
 * Used for financial reporting and forecasting.
 */
export const costBaselines = pgTable(
  'cost_baselines',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    fiscalYear: integer('fiscal_year').notNull(),
    depotId: uuid('depot_id').references(() => depots.id),

    // Budget
    budgetLaborHours: decimal('budget_labor_hours', { precision: 12, scale: 2 }),
    budgetLaborCost: decimal('budget_labor_cost', { precision: 14, scale: 2 }),
    budgetMaterialCost: decimal('budget_material_cost', { precision: 14, scale: 2 }),
    budgetTotal: decimal('budget_total', { precision: 14, scale: 2 }),

    // Actuals (updated monthly)
    actualLaborHours: decimal('actual_labor_hours', { precision: 12, scale: 2 }),
    actualLaborCost: decimal('actual_labor_cost', { precision: 14, scale: 2 }),
    actualMaterialCost: decimal('actual_material_cost', { precision: 14, scale: 2 }),
    actualTotal: decimal('actual_total', { precision: 14, scale: 2 }),

    // Generated column: cost variance percentage (positive = over-budget)
    variancePct: decimal('variance_pct', { precision: 5, scale: 2 }).generatedAlwaysAs(
      sql`CASE WHEN budget_total > 0 THEN ((actual_total - budget_total) / budget_total * 100) ELSE 0 END`
    ),

    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_cost_baselines_year_depot').on(table.fiscalYear, table.depotId),
    index('idx_cost_baselines_year').on(table.fiscalYear),
  ]
);

