/**
 * MMS Maximo Integration Tables
 *
 * Shadow records that mirror Maximo work orders, allowing operations to continue
 * if Maximo is unavailable. Implements the shadow record pattern from spec 007.
 *
 * Key concepts:
 * - MMS maintains scheduling data as source of truth
 * - Shadow records track sync state with Maximo
 * - Status-based locking: INPRG work orders are read-only in MMS
 * - Conflict resolution when both systems change data
 *
 * @see specs/007-integration.md Section 7.4
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  decimal,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { maximoSyncStatusEnum, maximoWoStatusEnum } from './enums';
import { pmSchedule } from './pm-management';
import { users } from './users';

/**
 * Maximo Shadow Records - mirrors Maximo work orders
 *
 * Each PM schedule entry can have a corresponding shadow record that tracks
 * the sync state with Maximo. This enables:
 * - Offline operation when Maximo is unavailable
 * - Conflict detection and resolution
 * - Status-based edit locking (INPRG = read-only)
 * - Audit trail of synchronization events
 *
 * Status transitions:
 * - PENDING: Created in MMS, awaiting sync to Maximo
 * - SYNCED: Successfully synchronized
 * - CONFLICT: Data changed in both systems since last sync
 * - ERROR: Sync attempt failed
 *
 * @see specs/007-integration.md Section 7.4.2
 */
export const maximoShadowRecords = pgTable(
  'maximo_shadow_records',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Link to MMS PM schedule (1:1 relationship)
    pmScheduleId: uuid('pm_schedule_id')
      .notNull()
      .unique()
      .references(() => pmSchedule.id, { onDelete: 'cascade' }),

    // Maximo work order reference
    maximoWoNum: varchar('maximo_wo_num', { length: 50 }),
    maximoWoId: varchar('maximo_wo_id', { length: 100 }), // Maximo internal ID

    // Sync status
    syncStatus: maximoSyncStatusEnum('sync_status').notNull().default('PENDING'),
    lastSyncAt: timestamp('last_sync_at', { withTimezone: true }),
    lastSyncError: text('last_sync_error'),
    syncAttempts: integer('sync_attempts').default(0),
    nextSyncAt: timestamp('next_sync_at', { withTimezone: true }),

    // MMS data snapshot at last sync (for conflict detection)
    mmsDataSnapshot: jsonb('mms_data_snapshot').$type<{
      trainId: string;
      pmTypeCode: string;
      targetDate: string;
      status: string;
      assignedDepotId?: string;
      assignedHours?: string;
    }>(),

    // Maximo data received from last sync
    maximoData: jsonb('maximo_data').$type<{
      status: string;
      schedStart?: string;
      schedFinish?: string;
      actualStart?: string;
      actualFinish?: string;
      actualLabor?: number;
      changeDate?: string;
    }>(),

    // Pending changes waiting to be synced to Maximo
    pendingChanges: jsonb('pending_changes').$type<{
      targetDate?: string;
      assignedDepotId?: string;
      assignedHours?: number;
    }>(),

    // Conflict resolution
    conflictResolvedAt: timestamp('conflict_resolved_at', { withTimezone: true }),
    conflictResolvedBy: uuid('conflict_resolved_by').references(() => users.id),
    conflictResolution: varchar('conflict_resolution', { length: 20 }), // 'USE_MMS' | 'USE_MAXIMO'

    // Metadata
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    uniqueIndex('idx_maximo_shadow_pm').on(table.pmScheduleId),
    index('idx_maximo_shadow_wo').on(table.maximoWoNum),
    index('idx_maximo_shadow_status').on(table.syncStatus),
    index('idx_maximo_shadow_next_sync').on(table.nextSyncAt),
  ]
);

/**
 * Maximo Sync History - audit trail for sync operations
 *
 * Records every sync attempt for debugging and compliance.
 */
export const maximoSyncHistory = pgTable(
  'maximo_sync_history',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    shadowRecordId: uuid('shadow_record_id')
      .notNull()
      .references(() => maximoShadowRecords.id, { onDelete: 'cascade' }),

    // Sync operation details
    operation: varchar('operation', { length: 20 }).notNull(), // 'PUSH' | 'PULL' | 'CONFLICT_RESOLVE'
    previousStatus: maximoSyncStatusEnum('previous_status'),
    newStatus: maximoSyncStatusEnum('new_status'),
    maximoStatus: maximoWoStatusEnum('maximo_status'),

    // Request/response data
    requestData: jsonb('request_data'),
    responseData: jsonb('response_data'),

    // Result
    success: boolean('success').notNull(),
    errorCode: varchar('error_code', { length: 50 }),
    errorMessage: text('error_message'),

    // Timing
    startedAt: timestamp('started_at', { withTimezone: true }).notNull(),
    completedAt: timestamp('completed_at', { withTimezone: true }),
    durationMs: integer('duration_ms'),

    // Context
    triggeredBy: varchar('triggered_by', { length: 50 }), // 'SCHEDULER' | 'WEBHOOK' | 'USER' | 'API'
    userId: uuid('user_id').references(() => users.id),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_maximo_sync_history_shadow').on(table.shadowRecordId),
    index('idx_maximo_sync_history_time').on(table.startedAt),
    index('idx_maximo_sync_history_status').on(table.newStatus),
  ]
);

/**
 * Maximo Integration Config - per-depot Maximo settings
 *
 * Stores depot-specific Maximo configuration for multi-site deployments.
 */
export const maximoIntegrationConfig = pgTable(
  'maximo_integration_config',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Scope (NULL = global default)
    depotId: uuid('depot_id'),

    // Maximo connection settings
    baseUrl: varchar('base_url', { length: 255 }).notNull(),
    siteId: varchar('site_id', { length: 50 }).notNull().default('METRO'),
    username: varchar('username', { length: 100 }).notNull(),
    // Note: Password stored in external secrets manager, not in DB

    // Sync settings
    syncEnabled: boolean('sync_enabled').default(true),
    pollIntervalMinutes: integer('poll_interval_minutes').default(15),
    pushDelaySeconds: integer('push_delay_seconds').default(5), // Debounce rapid changes

    // Retry settings
    maxRetries: integer('max_retries').default(5),
    retryBackoffMultiplier: decimal('retry_backoff_multiplier', { precision: 3, scale: 1 }).default(
      '2.0'
    ),
    initialRetryDelayMs: integer('initial_retry_delay_ms').default(1000),
    maxRetryDelayMs: integer('max_retry_delay_ms').default(60000),

    // Circuit breaker settings
    circuitBreakerFailures: integer('circuit_breaker_failures').default(5),
    circuitBreakerTimeout: integer('circuit_breaker_timeout').default(60000),

    // Status
    lastHealthCheckAt: timestamp('last_health_check_at', { withTimezone: true }),
    lastHealthCheckStatus: varchar('last_health_check_status', { length: 20 }),
    circuitBreakerState: varchar('circuit_breaker_state', { length: 20 }).default('CLOSED'),

    active: boolean('active').default(true),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [index('idx_maximo_config_depot').on(table.depotId)]
);

/**
 * Maximo Inventory Snapshots - cached inventory data from Maximo
 *
 * Stores periodic inventory snapshots for material availability checking.
 * MMS does not manage inventory - it consumes snapshots from Maximo.
 *
 * @see specs/007-integration.md Section 7.4.7
 */
export const maximoInventorySnapshots = pgTable(
  'maximo_inventory_snapshots',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Snapshot metadata
    snapshotAt: timestamp('snapshot_at', { withTimezone: true }).notNull().defaultNow(),
    depotId: uuid('depot_id').notNull(),
    partNumber: varchar('part_number', { length: 50 }).notNull(),

    // Maximo data
    maximoItemNum: varchar('maximo_item_num', { length: 50 }),
    description: text('description'),
    currentBalance: integer('current_balance').notNull().default(0),
    reservedQty: integer('reserved_qty').notNull().default(0),
    onOrderQty: integer('on_order_qty').notNull().default(0),
    reorderPoint: integer('reorder_point'),
    avgCost: decimal('avg_cost', { precision: 12, scale: 2 }),

    // Source tracking
    sourceSystem: varchar('source_system', { length: 20 }).default('MAXIMO'),
    maximoLocation: varchar('maximo_location', { length: 50 }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_maximo_inventory_depot_part').on(table.depotId, table.partNumber),
    index('idx_maximo_inventory_snapshot').on(table.snapshotAt),
  ]
);

