export const maximoShadowRecordsRelations = relations(maximoShadowRecords, ({ one, many }) => ({
  pmScheduleEntry: one(pmSchedule, {
    fields: [maximoShadowRecords.pmScheduleId],
    references: [pmSchedule.id],
  }),
  resolvedByUser: one(users, {
    fields: [maximoShadowRecords.conflictResolvedBy],
    references: [users.id],
  }),
  syncHistory: many(maximoSyncHistory),
}));

export const maximoSyncHistoryRelations = relations(maximoSyncHistory, ({ one }) => ({
  shadowRecord: one(maximoShadowRecords, {
    fields: [maximoSyncHistory.shadowRecordId],
    references: [maximoShadowRecords.id],
  }),
  user: one(users, {
    fields: [maximoSyncHistory.userId],
    references: [users.id],
  }),
}));

/**
 * Maximo Webhook Health - tracks webhook delivery status for polling fallback
 *
 * When webhooks become unreliable (no delivery for configured timeout),
 * the system automatically activates polling fallback mode.
 *
 * Sync modes:
 * - WEBHOOK: Primary mode, webhooks deliver real-time updates
 * - POLLING: Fallback mode, scheduled pulls every N minutes
 * - HYBRID: Both active during transition periods
 *
 * @see specs/007-integration.md Section 7.4.7
 */
export const maximoWebhookHealth = pgTable(
  'maximo_webhook_health',
  {
    id: uuid('id').primaryKey().defaultRandom(),

    // Scope (NULL = global)
    depotId: uuid('depot_id'),

    // Webhook tracking
    lastWebhookReceivedAt: timestamp('last_webhook_received_at', { withTimezone: true }),
    lastWebhookEventType: varchar('last_webhook_event_type', { length: 50 }),
    webhookConsecutiveFailures: integer('webhook_consecutive_failures').default(0),
    webhookLastFailureAt: timestamp('last_failure_at', { withTimezone: true }),
    webhookLastError: text('webhook_last_error'),

    // Polling state
    pollingEnabled: boolean('polling_enabled').default(false),
    pollingActivatedAt: timestamp('polling_activated_at', { withTimezone: true }),
    lastPollAt: timestamp('last_poll_at', { withTimezone: true }),
    lastPollResult: jsonb('last_poll_result').$type<{
      processed: number;
      updated: number;
      conflicts: number;
      errors: number;
      durationMs: number;
    }>(),
    pollingConsecutiveFailures: integer('polling_consecutive_failures').default(0),

    // Sync mode
    syncMode: varchar('sync_mode', { length: 20 }).default('WEBHOOK'), // WEBHOOK | POLLING | HYBRID

    // Configuration overrides (NULL = use global config)
    webhookTimeoutMinutes: integer('webhook_timeout_minutes'), // Default: 30 min
    pollingIntervalMinutes: integer('polling_interval_minutes'), // Default: 15 min
    gracePeriodMinutes: integer('grace_period_minutes'), // After webhook recovery, keep polling: 5 min

    // Deduplication tracking
    lastProcessedChangeTimestamp: timestamp('last_processed_change_timestamp', { withTimezone: true }),
    deduplicationWindowMs: integer('deduplication_window_ms').default(5000),

    // Metrics
    totalWebhooksReceived: integer('total_webhooks_received').default(0),
    totalPollsExecuted: integer('total_polls_executed').default(0),
    totalDuplicatesPrevented: integer('total_duplicates_prevented').default(0),
    totalFallbackActivations: integer('total_fallback_activations').default(0),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_webhook_health_depot').on(table.depotId),
    index('idx_webhook_health_mode').on(table.syncMode),
  ]
);

/**
 * MMS Users & Authentication Tables
 *
 * Access control and session management for the MMS system.
 * Supports RBAC (Role-Based Access Control) with fine-grained permissions.
 *
 * @see specs/003-database-schema.md Section 3.12
 */

import { relations } from 'drizzle-orm';
import {
  boolean,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { depots } from './core-fleet';

/**
 * Users - System users
 *
 * Includes planners, depot managers, system admins, and technicians.
 * Each user can have certifications (for technician constraint matching).
 */
export const users = pgTable(
  'users',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    email: varchar('email', { length: 255 }).notNull().unique(),
    passwordHash: varchar('password_hash', { length: 255 }).notNull(),

    firstName: varchar('first_name', { length: 100 }),
    lastName: varchar('last_name', { length: 100 }),
    displayName: varchar('display_name', { length: 200 }),

    // Assignment
    primaryDepotId: uuid('primary_depot_id').references(() => depots.id),
    roleIds: text('role_ids').array().notNull().default([]),

    // Certifications (for technician constraint matching)
    certifications: text('certifications').array(),

    // Status
    isActive: boolean('is_active').default(true),
    lastLoginAt: timestamp('last_login_at', { withTimezone: true }),
    failedLoginAttempts: integer('failed_login_attempts').default(0),
    lockedUntil: timestamp('locked_until', { withTimezone: true }),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    updatedAt: timestamp('updated_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_users_email').on(table.email),
    index('idx_users_depot').on(table.primaryDepotId),
  ]
);

/**
 * Roles - Permission groups
 *
 * Standard roles include:
 * - PLANNER: Can create/modify PM schedules
 * - DEPOT_MANAGER: Manages depot-specific operations
 * - SYSTEM_ADMIN: Full system access
 * - VIEWER: Read-only access
 *
 * Permissions are stored as JSONB for flexibility:
 * { "pm_schedule": ["read", "write"], "baseline": ["read"] }
 */
export const roles = pgTable('roles', {
  id: uuid('id').primaryKey().defaultRandom(),
  name: varchar('name', { length: 50 }).notNull().unique(),
  description: text('description'),
  permissions: jsonb('permissions').notNull(), // e.g., {"pm_schedule": ["read", "write"]}
  createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
});

/**
 * Sessions - User sessions
 *
 * Note: In production, sessions are typically stored in Redis for performance.
 * This table provides a fallback and audit trail.
 */
export const sessions = pgTable(
  'sessions',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    userId: uuid('user_id')
      .notNull()
      .references(() => users.id),
    tokenHash: varchar('token_hash', { length: 255 }).notNull(),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).notNull(),
    lastActivityAt: timestamp('last_activity_at', { withTimezone: true }).defaultNow(),

    ipAddress: varchar('ip_address', { length: 45 }), // IPv6 max length
    userAgent: text('user_agent'),
  },
  (table) => [index('idx_sessions_user').on(table.userId), index('idx_sessions_expiry').on(table.expiresAt)]
);

// ============================================================================
// Relations
// ============================================================================

export const usersRelations = relations(users, ({ one, many }) => ({
  primaryDepot: one(depots, {
    fields: [users.primaryDepotId],
    references: [depots.id],
  }),
  sessions: many(sessions),
}));

export const sessionsRelations = relations(sessions, ({ one }) => ({
  user: one(users, {
    fields: [sessions.userId],
    references: [users.id],
  }),
}));

/**
 * MMS Scenario Management Tables
 *
 * Event-sourced what-if analysis for PM schedule planning.
 *
 * Scenarios allow planners to:
 * - Fork from a baseline or another scenario
 * - Make changes (PM_MOVE, PM_ADD, PM_REMOVE, etc.)
 * - Compare scenarios side-by-side
 * - Promote winning scenario to new baseline
 *
 * Event sourcing: Changes are stored as deltas, not mutations.
 * This allows replaying history and comparing states.
 *
 * @see specs/003-database-schema.md Section 3.9
 */

import { relations, sql } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { scenarioStatusEnum } from './enums';
import { planBaselines } from './baseline-drift';
import { users } from './users';

/**
 * Scenarios - What-if analysis containers
 *
 * Each scenario forks from a baseline or another scenario.
 * Changes are tracked as deltas for full history replay.
 *
 * Auto-expiration: Inactive scenarios expire after 30 days.
 */
export const scenarios = pgTable(
  'scenarios',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),

    // Fork point
    forkedFromBaselineId: uuid('forked_from_baseline_id').references(() => planBaselines.id),
    forkedFromScenarioId: uuid('forked_from_scenario_id'),
    forkedAt: timestamp('forked_at', { withTimezone: true }).defaultNow(),

    // Metadata
    status: scenarioStatusEnum('status').default('ACTIVE'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    // Expiration (auto-expire after 30 days of inactivity)
    lastModifiedAt: timestamp('last_modified_at', { withTimezone: true }).defaultNow(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).default(
      sql`NOW() + INTERVAL '30 days'`
    ),

    // Promotion
    promotedToBaselineId: uuid('promoted_to_baseline_id').references(() => planBaselines.id),
    promotedAt: timestamp('promoted_at', { withTimezone: true }),
    promotedBy: uuid('promoted_by').references(() => users.id),
  },
  (table) => [
    index('idx_scenarios_status').on(table.status),
    index('idx_scenarios_user').on(table.createdBy, table.status),
    index('idx_scenarios_expiring').on(table.expiresAt),
  ]
);

/**
 * Scenario Deltas - Event-sourced changes
 *
 * Each delta represents a change made to the scenario.
 * Changes are applied in sequence_num order.
 *
 * Delta types:
 * - PM_MOVE: Reschedule PM to new date
 * - PM_ADD: Insert new PM
 * - PM_REMOVE: Delete PM
 * - CAPACITY_CHANGE: Modify man-hour capacity
 * - TRAIN_STATUS_CHANGE: Update train fitness/restrictions
 */
export const scenarioDeltas = pgTable(
  'scenario_deltas',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    scenarioId: uuid('scenario_id')
      .notNull()
      .references(() => scenarios.id, { onDelete: 'cascade' }),
    sequenceNum: integer('sequence_num').notNull(),

    deltaType: varchar('delta_type', { length: 50 }).notNull(),
    // 'PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE'

    // Reference to affected entity
    entityType: varchar('entity_type', { length: 50 }).notNull(), // 'pm_schedule', 'manhour_capacity', etc.
    entityId: uuid('entity_id').notNull(),

    // Change details
    oldValues: jsonb('old_values'),
    newValues: jsonb('new_values'),

    // Explanation
    changeReason: text('change_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [
    uniqueIndex('idx_scenario_deltas_unique').on(table.scenarioId, table.sequenceNum),
    index('idx_scenario_deltas_scenario').on(table.scenarioId, table.sequenceNum),
  ]
);

/**
 * Scenario Comparisons - Pre-computed comparison results
 *
 * Materialized comparison between two scenarios or a scenario and baseline.
 * Created on-demand when user requests comparison.
 */
export const scenarioComparisons = pgTable(
  'scenario_comparisons',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    scenarioAId: uuid('scenario_a_id')
      .notNull()
      .references(() => scenarios.id),
    scenarioBId: uuid('scenario_b_id').references(() => scenarios.id), // NULL = compare to baseline
    baselineId: uuid('baseline_id').references(() => planBaselines.id),

    comparisonDate: date('comparison_date').notNull(),

    // Summary metrics
    pmCountDelta: integer('pm_count_delta'),
